import React, { useState, useEffect } from 'react';
import './ReviewSection.css';

const ReviewSection = ({ batchId }) => {
  const [reviews, setReviews] = useState([]);
  const [newReview, setNewReview] = useState({ consumerName: '', rating: 0, comment: '' });
  const [loading, setLoading] = useState(true);
  const [submitting, setSubmitting] = useState(false);
  const [error, setError] = useState('');

  useEffect(() => {
    fetchReviews();
  }, [batchId]);

  const fetchReviews = async () => {
    try {
      const response = await fetch(`http://localhost:8080/api/reviews/batch/${batchId}`);
      if (response.ok) {
        const data = await response.json();
        setReviews(data);
      }
    } catch (err) {
      console.error("Failed to load reviews:", err);
    } finally {
      setLoading(false);
    }
  };

  const handleRating = (rating) => {
    setNewReview(prev => ({ ...prev, rating }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (newReview.rating === 0) {
      setError('Please select a star rating.');
      return;
    }
    if (!newReview.comment.trim()) {
      setError('Please provide a comment.');
      return;
    }

    try {
      setSubmitting(true);
      setError('');
      const reviewPayload = {
        batchId: String(batchId),
        consumerName: newReview.consumerName || 'Anonymous Consumer',
        rating: newReview.rating,
        comment: newReview.comment,
        timestamp: new Date().toISOString()
      };

      const response = await fetch('http://localhost:8080/api/reviews', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json'
        },
        body: JSON.stringify(reviewPayload)
      });

      if (response.ok) {
        const savedReview = await response.json();
        setReviews([savedReview, ...reviews]);
        setNewReview({ consumerName: '', rating: 0, comment: '' });
      } else {
        throw new Error('Failed to submit review');
      }
    } catch (err) {
      setError(err.message || 'An error occurred while submitting.');
    } finally {
      setSubmitting(false);
    }
  };

  const calculateAverageRating = () => {
    if (reviews.length === 0) return 0;
    const sum = reviews.reduce((acc, rev) => acc + rev.rating, 0);
    return (sum / reviews.length).toFixed(1);
  };

  return (
    <div className="review-section-container">
      <div className="review-header">
        <h2 className="trace-title">Consumer Feedback</h2>
        <div className="review-stats">
          <span className="avg-rating">{calculateAverageRating()}</span>
          <span className="star-icon">★</span>
          <span className="total-reviews">({reviews.length} reviews)</span>
        </div>
      </div>

      {loading ? (
        <div className="loader"></div>
      ) : (
        <div className="review-content">
          <div className="review-form-container glass-card">
            <h3>Leave a Review</h3>
            <p className="verified-badge">✔ Verified Purchase</p>
            {error && <div className="error-message">{error}</div>}

            <form onSubmit={handleSubmit} className="review-form">
              <div className="rating-selector">
                {[1, 2, 3, 4, 5].map(star => (
                  <span 
                    key={star} 
                    className={`star-select ${star <= newReview.rating ? 'active' : ''}`}
                    onClick={() => handleRating(star)}
                  >
                    ★
                  </span>
                ))}
              </div>

              <input
                type="text"
                placeholder="Your Name (Optional)"
                value={newReview.consumerName}
                onChange={(e) => setNewReview({...newReview, consumerName: e.target.value})}
                className="review-input"
              />

              <textarea
                placeholder="Share your feedback about this product..."
                value={newReview.comment}
                onChange={(e) => setNewReview({...newReview, comment: e.target.value})}
                className="review-textarea"
                rows="4"
              ></textarea>

              <button type="submit" disabled={submitting} className="submit-btn primary-btn">
                {submitting ? 'Submitting...' : 'Submit Review'}
              </button>
            </form>
          </div>

          <div className="reviews-list">
            {reviews.length === 0 ? (
              <p className="empty-reviews">Be the first to review this product!</p>
            ) : (
              reviews.map((rev, index) => (
                <div key={rev.id || index} className="review-item glass-card">
                  <div className="review-item-header">
                    <span className="reviewer-name">{rev.consumerName}</span>
                    <span className="review-date">
                      {new Date(rev.timestamp).toLocaleDateString()}
                    </span>
                  </div>
                  <div className="review-item-rating">
                    {[1, 2, 3, 4, 5].map(star => (
                      <span key={star} className={`star-display ${star <= rev.rating ? 'filled' : ''}`}>
                        ★
                      </span>
                    ))}
                  </div>
                  <p className="review-comment">{rev.comment}</p>
                </div>
              ))
            )}
          </div>
        </div>
      )}
    </div>
  );
};

export default ReviewSection;
